{"npsn":"70037401","name":"SMP ALKHAIRAAT BOU","address":"Jl. Trans Palu - Toli-Toli","village":"Bou","status":"Swasta","jenjang":"SMP","district":"Sojol","regencyBpsCode":"7203","regencyName":"Kabupaten Donggala","provinceName":"Sulawesi Tengah","school_id":"4b1d5e32-469e-4fc0-bf80-76befb79c064","user_id":"c9b4ee27-4b86-45c3-9339-5d9adfe49ed7","password_hash":"$2b$04$rFfGfqBvEag6BnEdQyBnru8bLoLzRioSA.4RpP6IVE.Q6O7yOKx86"},
